const nombre = $input.item.json.cliente_nombre || 'Amigo';
const mensajes = [
  `¡Hola ${nombre}! 👋 Qué bueno verte aquí. Vamos a trabajar en tu web para que atraiga clientes.`,
  `¡Bienvenido ${nombre}! 🚀 Me alegra ayudarte a crecer tu negocio con una web que funcione.`,
  `¡Hola ${nombre}! ✨ Vamos a crear algo increíble para tu negocio.`
];
const mensaje = mensajes[Math.floor(Math.random() * mensajes.length)];
return { ...($input.item.json), mensaje_actual: mensaje, bloque_actual: 'bienvenida', siguiente_bloque: 'educacion' };

const nombre = $input.item.json.cliente_nombre || 'Amigo';
const mensaje = `${nombre}, hoy si no estás en internet, es como si no existieras. 🌐

El 87% de clientes buscan en Google antes de comprar. Tu web optimizada permite que te encuentren.

Cada visita orgánica es un cliente potencial. Es como tener vendedores 24/7. 📈

Con Facebook Pixel, tus anuncios se optimizan automáticamente.`;
return { ...($input.item.json), mensaje_actual: mensaje, bloque_actual: 'educacion', siguiente_bloque: 'filtrado' };

const nombre = $input.item.json.cliente_nombre || 'Amigo';
const mensaje = `${nombre}, necesito hacerte 3 preguntas rápidas 📋

1️⃣ ¿Tu negocio ya está funcionando y atendiendo clientes hoy?

2️⃣ ¿Quieres usar esta web para atraer más clientes?

3️⃣ ¿Planeas mantener tu negocio activo los próximos meses?

👆 Responde SÍ o NO a cada pregunta`;
return { ...($input.item.json), mensaje_actual: mensaje, bloque_actual: 'filtrado', siguiente_bloque: 'evaluar_score' };

const respuestas = $input.item.json.respuestas_cliente || $input.item.json.body?.respuestas || {};
const esPositivo = (r) => { if (!r) return false; const x = r.toString().toLowerCase(); return ['sí','si','yes','claro','dale','ok'].includes(x); };
const negocio_activo = esPositivo(respuestas.pregunta_1) ? 1 : 0;
const intencion_crecimiento = esPositivo(respuestas.pregunta_2) ? 1 : 0;
const horizonte_continuidad = esPositivo(respuestas.pregunta_3) ? 1 : 0;
const score_cliente = negocio_activo + intencion_crecimiento + horizonte_continuidad;
return { ...($input.item.json), negocio_activo, intencion_crecimiento, horizonte_continuidad, score_cliente, cliente_calificado: score_cliente >= 3 };

const nombre = $input.item.json.cliente_nombre || 'Amigo';
const mensaje = `¡Genial ${nombre}! 🎉 Tu negocio califica. Vamos a crear tu web GRATIS, paso a paso.`;
return { ...($input.item.json), mensaje_actual: mensaje, bloque_actual: 'validacion' };

const nombre = $input.item.json.cliente_nombre || 'Amigo';
const mensaje = `${nombre}, gracias por tu tiempo. 🙏 Este servicio es para negocios activos. Cuando estés listo, vuelve. ¡Éxito!`;
return { ...($input.item.json), mensaje_actual: mensaje, flujo_terminado: true };

const nombre = $input.item.json.cliente_nombre || 'Amigo';
const mensaje = `${nombre}, así funciona 📋

✅ Web profesional GRATIS
✅ SEO optimizado
✅ Facebook Pixel

💡 El hosting es como alquiler digital: $29.29/mes para mantener tu web activa 24/7.

🎁 La web es GRATIS. Solo pagas hosting.`;
return { ...($input.item.json), mensaje_actual: mensaje, precio_hosting: 29.29 };

const nombre = $input.item.json.cliente_nombre || 'Amigo';
const mensaje = `¡Perfecto ${nombre}! 📝 Necesito info de tu negocio:

1. Nombre del negocio
2. Ciudad/zona
3. Email
4. Redes sociales
5. Servicios/productos
6. Colores de marca
7. ¿Tienes logo?`;
return { ...($input.item.json), mensaje_actual: mensaje };

const nombre = $input.item.json.cliente_nombre || 'Amigo';
const mensaje = `🎉 ¡Listo ${nombre}!

📅 Próximos pasos:
1. Diseño (3-5 días)
2. Tu aprobación
3. Activar hosting ($29.29/mes)
4. ¡Web online!

¿Alguna pregunta?`;
return { ...($input.item.json), mensaje_actual: mensaje, flujo_completado: true };
